// Parse MCP response and extract recommendations
const body = $input.first().json;
const text = body?.result?.content?.[0]?.text || '{}';
let recs = [];
try {
  const parsed = JSON.parse(text);
  recs = parsed.recommendations || [];
} catch(e) {
  return [{ json: { error: 'Failed to parse MCP response', raw: text } }];
}

// Filter: only high priority, >$100/month savings
const filtered = recs.filter(r => 
  r.estimated_savings_usd > 100 && 
  (r.priority === 'high' || r.effort_level === 'low')
);

return filtered.map(r => ({ json: r }));

// Extract remediation ID from MCP response
const body = $input.first().json;
const text = body?.result?.content?.[0]?.text || '';

// Parse remediation ID from markdown response
const match = text.match(/\*\*Remediation ID\*\*: `([^`]+)`/);
const remId = match ? match[1] : null;

return [{ json: { 
  remediation_id: remId, 
  resource_id: $('Filter High-Value Recs').item.json.resource_id,
  mcp_response: text 
} }];
